// Filter: only process emails from Easy/Logfire about Musan
const subject = ($json.subject || '').toLowerCase();
const from = ($json.from || '').toLowerCase();

if (subject.includes('musan') && from.includes('logfire')) {
  return [$input.first()];
}

// No match — stop execution
return [];

// XLSX rows come as arrays: item.json.row = [val0, val1, ...]
// Row 0 = metadata (skip), Row 1 = headers, Row 2+ = data
const items = $input.all();
const OPERATOR_ID = '92dc5797-047d-458d-bbdb-63f18c0dd1e7';
const CLIENT_ID = 'acf3d096-1ff6-4157-9b69-cab6e6a5789f';

const emailItem = $('Email Trigger (IMAP)').first();
const binaryKeys = Object.keys(emailItem.binary || {});
const fileName = binaryKeys.length > 0
  ? (emailItem.binary[binaryKeys[0]].fileName || 'unknown.xlsx')
  : 'unknown.xlsx';

if (items.length < 3) {
  throw new Error('Not enough rows: ' + items.length);
}

// Row 1 (index 1) contains the header names
const headers = items[1].json.row;
const colIdx = {};
headers.forEach((h, i) => { if (h) colIdx[String(h).trim()] = i; });

function col(row, name) {
  const i = colIdx[name];
  if (i === undefined) return '';
  return String(row[i] != null ? row[i] : '').trim();
}

function rowToObj(row) {
  const obj = {};
  headers.forEach((h, i) => { if (h && row[i] != null) obj[String(h).trim()] = row[i]; });
  return obj;
}

const ordersMap = new Map();
const packages = [];
const errors = [];

function cleanPhone(phone) {
  if (!phone) return '';
  let cleaned = phone.replace(/[\s\-\.\(\)]/g, '');
  if (/^9\d{8}$/.test(cleaned)) cleaned = '+56' + cleaned;
  if (/^569\d{8}$/.test(cleaned)) cleaned = '+' + cleaned;
  return cleaned;
}

function parseDate(dateStr) {
  if (!dateStr) return null;
  const num = Number(dateStr);
  if (!isNaN(num) && num > 40000 && num < 60000) {
    const d = new Date((num - 25569) * 86400 * 1000);
    return d.toISOString().split('T')[0];
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) return dateStr;
  const m = dateStr.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
}

// Data starts at row index 2
for (let i = 2; i < items.length; i++) {
  const row = items[i].json.row;
  if (!row || !Array.isArray(row)) continue;
  const rowNum = i + 1;
  const rawData = rowToObj(row);

  const entrega = col(row, 'Entrega');
  const carton = col(row, 'Cartón') || col(row, 'Carton');
  const address = col(row, 'Direccion');
  const rawDate = col(row, 'Fecha Entrega');
  const parsedDate = parseDate(rawDate);

  if (!entrega) {
    errors.push({ row: rowNum, reason: 'Missing Entrega' });
    continue;
  }
  if (!address) {
    errors.push({ row: rowNum, reason: 'Missing Direccion' });
    continue;
  }

  const cleanedPhone = cleanPhone(col(row, 'Telefono'));

  if (!ordersMap.has(entrega)) {
    ordersMap.set(entrega, {
      operator_id: OPERATOR_ID,
      order_number: entrega,
      external_load_id: col(row, 'Nro Carga'),
      customer_name: col(row, 'Nombre'),
      customer_phone: cleanedPhone,
      delivery_address: address,
      comuna: col(row, 'Comuna'),
      recipient_region: col(row, 'Región') || col(row, 'Region'),
      delivery_date: parsedDate,
      service_type: col(row, 'Tipo Orden'),
      retailer_name: 'Easy',
      imported_via: 'EMAIL',
      source_file: fileName,
      tenant_client_id: CLIENT_ID,
      imported_at: new Date().toISOString(),
      metadata: {
        customer_email: col(row, 'Correo'),
        distribution_center: col(row, 'CD'),
        dock: col(row, 'Anden'),
        complement: col(row, 'Compl')
      },
      raw_data: rawData
    });
  }

  if (carton) {
    packages.push({
      operator_id: OPERATOR_ID,
      order_number: entrega,
      label: carton,
      sku_items: [{
        sku: col(row, 'Producto'),
        description: col(row, 'Descripcion'),
        quantity: parseInt(col(row, 'Unid') || col(row, 'Cant') || '1', 10) || 1
      }],
      declared_box_count: parseInt(col(row, 'Bultos') || '1', 10) || 1,
      raw_data: rawData
    });
  }
}

const orders = Array.from(ordersMap.values());

if (orders.length === 0) {
  throw new Error('No valid orders (' + items.length + ' rows, ' + errors.length + ' errors). Headers: ' + headers.join(','));
}

return [{ json: {
  orders,
  packages,
  rows_processed: items.length - 2,
  orders_count: orders.length,
  packages_count: packages.length,
  rows_skipped: errors.length,
  errors: errors.slice(0, 20),
  operator_id: OPERATOR_ID,
  client_id: CLIENT_ID,
  file_name: fileName
}}];

// Map order_number -> order_id from UPSERT Orders response
const orderItems = $input.all();
const orders = orderItems.map(item => item.json);
const packages = $('Map & Validate').first().json.packages;

const orderIds = {};
for (const o of orders) {
  if (o.order_number && o.id) {
    orderIds[o.order_number] = o.id;
  }
}

const packageBodies = packages
  .filter(p => orderIds[p.order_number])
  .map(p => ({
    operator_id: p.operator_id,
    order_id: orderIds[p.order_number],
    label: p.label,
    sku_items: p.sku_items,
    declared_box_count: p.declared_box_count,
    raw_data: p.raw_data
  }));

return [{ json: {
  packages: packageBodies,
  orders_upserted: orders.length,
  packages_count: packageBodies.length
}}];

// Prepare job completion data
const mapData = $('Map & Validate').first().json;
const linkData = $('Link Packages').first().json;
const jobId = $('Create Job Record').first().json.id;
const allFailed = mapData.rows_skipped > 0 && linkData.orders_upserted === 0;

return [{ json: {
  job_id: jobId,
  patch_body: {
    status: allFailed ? 'failed' : 'completed',
    completed_at: new Date().toISOString(),
    result: {
      rows_processed: mapData.rows_processed,
      orders_upserted: linkData.orders_upserted,
      packages_inserted: linkData.packages_count,
      rows_skipped: mapData.rows_skipped,
      errors: mapData.errors
    },
    error_message: allFailed ? 'All rows failed validation (' + mapData.rows_skipped + ' skipped)' : null
  }
}}];

// Extract error info and job_id for failure handler
const error = $input.first().json;
let jobId = null;
try {
  const jobResp = $('Create Job Record').first();
  if (jobResp && jobResp.json) {
    jobId = jobResp.json.id || null;
  }
} catch(e) {
  // Create Job Record may not have executed
}

const errorMessage = String(error.message || error.description || JSON.stringify(error)).substring(0, 1000);

return [{ json: {
  job_id: jobId || 'null',
  patch_body: {
    status: 'failed',
    completed_at: new Date().toISOString(),
    error_message: errorMessage
  }
}}];
